import React, { useState, useEffect, useRef } from 'react';
import Tesseract from 'tesseract.js';
import { saveHistory } from '../services/api';
import { languages } from '../constants/languages';
import { preprocessImageForOCR } from '../utils/imagePreprocessing';

const CameraTranslator: React.FC = () => {
    const [image, setImage] = useState<string | null>(null);
    const [ocrText, setOcrText] = useState('');
    const [translatedText, setTranslatedText] = useState('');
    const [srcLang] = useState('eng_Latn');
    const [tgtLang, setTgtLang] = useState('fra_Latn');
    const [ocrProgress, setOcrProgress] = useState(0);
    const [translationProgress, setTranslationProgress] = useState<any>(null);
    const [status, setStatus] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const worker = useRef<Worker | null>(null);

    useEffect(() => {
        worker.current = new Worker(new URL('../worker.ts', import.meta.url), {
            type: 'module',
        });

        worker.current.onmessage = (e) => {
            const { status, output, error } = e.data;
            if (status === 'progress') {
                setTranslationProgress(e.data);
            } else if (status === 'complete') {
                const translated = output[0].translation_text;
                setTranslatedText(translated);
                setTranslationProgress(null);
                setIsLoading(false);
                setStatus('Translation complete');

                const username = localStorage.getItem('username') || 'anonymous';
                saveHistory({
                    username,
                    type: 'CAMERA_TRANSLATE',
                    sourceText: ocrText,
                    resultText: translated
                }).catch(err => console.error('History save failed', err));

            } else if (status === 'error') {
                setStatus('Translation Error: ' + error);
                setIsLoading(false);
            }
        };

        return () => worker.current?.terminate();
    }, [ocrText]);

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setImage(URL.createObjectURL(e.target.files[0]));
            setOcrText('');
            setTranslatedText('');
            setOcrProgress(0);
            setStatus('');
        }
    };

    const processImage = async () => {
        if (!image) return;
        setIsLoading(true);
        setStatus('Analyzing image...');
        setTranslatedText('');

        try {
            // Pre-process image locally for better OCR result
            setStatus('Optimizing image for AI...');
            const processedImage = await preprocessImageForOCR(image);

            // 1. OCR Step
            setStatus('Analyzing image...');
            const result = await Tesseract.recognize(processedImage, 'eng', {
                logger: (m) => {
                    if (m.status === 'recognizing text') setOcrProgress(m.progress * 100);
                }
            });

            const text = result.data.text.trim();
            setOcrText(text);

            if (!text) {
                setStatus('No text found in image.');
                setIsLoading(false);
                return;
            }

            // 2. Translation Step
            setStatus('Translating extracted text...');
            worker.current?.postMessage({
                text: text,
                src_lang: srcLang,
                tgt_lang: tgtLang,
            });

        } catch (err) {
            console.error(err);
            setStatus('Processing Error: ' + err);
            setIsLoading(false);
        }
    };

    return (
        <div className="p-4 max-w-5xl mx-auto space-y-8 min-h-screen pb-20 overflow-hidden">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <h1 className="text-4xl font-black mb-2 bg-gradient-to-r from-blue-600 to-indigo-500 bg-clip-text text-transparent">
                    Camera Translator
                </h1>
                <div className="flex items-center gap-3 p-2 bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
                    <span className="text-xs font-bold text-slate-400 uppercase ml-2">Target:</span>
                    <select
                        value={tgtLang}
                        onChange={(e) => setTgtLang(e.target.value)}
                        className="bg-transparent text-sm font-bold outline-none cursor-pointer pr-4"
                    >
                        {languages.map(lang => <option key={lang.code} value={lang.code}>{lang.name}</option>)}
                    </select>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Left Side: Input */}
                <div className="space-y-6">
                    <div className="p-8 bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-slate-200 dark:border-slate-700 relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-4 opacity-10 uppercase font-black text-4xl select-none group-hover:opacity-20 transition-opacity">Capture</div>

                        <label className="block text-sm font-black uppercase tracking-widest text-slate-400 mb-6 ml-1">Input Source</label>
                        <div className="relative">
                            <input
                                type="file"
                                accept="image/*"
                                capture="environment"
                                onChange={handleImageChange}
                                className="hidden"
                                id="camera-input"
                            />
                            <label
                                htmlFor="camera-input"
                                className="flex flex-col items-center justify-center w-full h-48 border-4 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl cursor-pointer hover:border-blue-500 hover:bg-blue-50/10 transition-all group/label"
                            >
                                <span className="text-4xl mb-3 group-hover/label:scale-110 transition-transform">????</span>
                                <span className="font-bold text-slate-500">Tap to Capture or Upload</span>
                                <span className="text-xs text-slate-400 mt-1">Supports PNG, JPG, WebP</span>
                            </label>
                        </div>

                        {image && (
                            <div className="mt-8 relative animate-in zoom-in-95 duration-500">
                                <img src={image} alt="Source" className="w-full rounded-[2rem] border-4 border-white dark:border-slate-700 shadow-2xl transition-all h-64 object-cover" />
                                <button
                                    onClick={processImage}
                                    disabled={isLoading}
                                    className="absolute -bottom-4 left-1/2 -translate-x-1/2 px-10 py-5 bg-blue-600 text-white rounded-2xl font-black shadow-[0_20px_40px_rgba(37,99,235,0.3)] hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 flex items-center gap-3 whitespace-nowrap z-20"
                                >
                                    {isLoading ? 'WORKING MAGIC...' : 'EXTRACT & TRANSLATE'}
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Right Side: Results */}
                <div className="space-y-8">
                    {isLoading && (
                        <div className="p-8 bg-blue-600/10 border border-blue-500/20 rounded-[2rem] backdrop-blur-3xl animate-in slide-in-from-top-4 duration-500 relative overflow-hidden">
                            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full animate-shimmer"></div>
                            <p className="text-xs font-black text-blue-500 mb-4 uppercase tracking-[0.3em]">{status}</p>
                            <div className="w-full bg-slate-200 dark:bg-slate-700 rounded-full h-3 mb-2 shadow-inner">
                                <div
                                    className="bg-blue-600 h-3 rounded-full transition-all duration-500 shadow-lg shadow-blue-500/50"
                                    style={{ width: `${ocrProgress || (translationProgress?.progress) || 0}%` }}
                                ></div>
                            </div>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest text-right">Processing Depth: {Math.round(ocrProgress || (translationProgress?.progress) || 0)}%</p>
                        </div>
                    )}

                    <div className="space-y-6">
                        <ResultCard title="Extracted Core Text" text={ocrText} icon="????" show={!!ocrText} />
                        <ResultCard title={`NEURA Translation (${languages.find(l => l.code === tgtLang)?.name})`} text={translatedText} icon="????" variant="indigo" show={!!translatedText} />
                    </div>

                    {!ocrText && !translatedText && !isLoading && (
                        <div className="h-full flex flex-col items-center justify-center p-12 text-slate-300 dark:text-slate-800 border-4 border-dashed border-slate-100 dark:border-slate-900 rounded-[3rem]">
                            <span className="text-8xl mb-4">????</span>
                            <p className="font-bold text-lg">Awaiting Intelligence</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

const ResultCard = ({ title, text, icon, show }: { title: string; text: string; icon: string; variant?: string; show: boolean }) => {
    if (!show) return null;
    return (
        <div className={`p-8 bg-white dark:bg-slate-800/50 backdrop-blur-2xl rounded-[2.5rem] shadow-2xl border border-slate-200 dark:border-slate-700 animate-in slide-in-from-right-8 duration-700`}>
            <div className="flex items-center gap-4 mb-6">
                <div className="w-12 h-12 flex items-center justify-center bg-slate-100 dark:bg-slate-900 rounded-2xl text-2xl">
                    {icon}
                </div>
                <h3 className="text-lg font-black tracking-tight">{title}</h3>
            </div>
            <p className="text-slate-600 dark:text-slate-200 text-xl leading-relaxed font-medium">
                {text || 'Analysing...'}
            </p>
        </div>
    );
};

export default CameraTranslator;

